// ----------------------------
// Get incoming data
// ----------------------------
const body = $input.item.json.body || {};

const userMessage = body.message || "";
const conversationHistory = body.conversationHistory || [];
const onboardingData = body.onboardingData || {};
const checklist = body.checklist || {};

// ------------------------------------------------
// PROGRAM ID HANDLING (reliable + persistent)
// ------------------------------------------------
let programId = body.programId || onboardingData.programId || null;

// Only save programId if valid (avoid undefined/N/A)
if (programId) {
  onboardingData.programId = programId;
}

// Dynamic implementation URL (safe fallback)
let implementationUrl = "";
if (onboardingData.programId) {
  implementationUrl = `https://hst.tradedoubler.com/file/${onboardingData.programId}/implementation.html`;
}

// ------------------------------------------------
// SAFETY RULE: Prevent mistakes in client name extraction
// ------------------------------------------------
onboardingData.disallowedNames = [
  "happy", "good", "ok", "great", "fine", "yes", "yep", "sure", "okay"
];

// ============================================
// NEW: SEARCH FOR SIMILAR PATTERNS
// ============================================

let learningContext = "";

// Only search if user message has substance
if (userMessage.trim().length > 10) {
  // Detect current topic for filtering
  const userLower = userMessage.toLowerCase();

  if (userLower.includes('cname') || userLower.includes('dns') || userLower.includes('subdomain')) {
    learningContext = `

📚 LEARNING FROM PAST SUCCESSES:
When clients ask about DNS/CNAME setup, successful approaches include:
- Using simple analogies (e.g., "CNAME is like forwarding mail to a different address")
- Emphasizing that they're just creating a forwarding rule, not building anything
- Offering to share DNS provider-specific instructions if they need help
- Being patient and breaking it down step by step
`;
  } else if (userLower.includes('gtm') || userLower.includes('tag manager') || userLower.includes('preview')) {
    learningContext = `

📚 LEARNING FROM PAST SUCCESSES:
For GTM questions, successful approaches include:
- Clearly stating that GTM Preview Mode CANNOT validate Tradedoubler tracking
- Explaining that the test MUST be done on the live site using the official test link
- Emphasizing that Preview Mode only confirms tags fire, but doesn't reach TD servers
- Offering to walk them through the proper testing process step by step
`;
  } else if (userLower.includes('confused') || userLower.includes('not sure') || userLower.includes('don\'t understand')) {
    learningContext = `

📚 LEARNING FROM PAST SUCCESSES:
When clients express confusion, successful approaches include:
- Acknowledging their confusion without judgment
- Breaking down complex topics into simple steps
- Using real-world analogies that relate to their business
- Offering to explain in a different way if needed
- Being patient and encouraging
`;
  }
}

// ------------------------------------------------
// SYSTEM PROMPT — KEEP YOUR CONTENT, JUST INSERT DYNAMIC VALUES
// ------------------------------------------------
const systemPrompt = `
You are an expert onboarding assistant for Tradedoubler, an affiliate marketing network. Guide clients through technical onboarding in a friendly, professional manner. Only greet the user once at the start of the conversation; once the conversation is flowing never repeat greetings such as Hi, Hello or Hey.

${learningContext}

CRITICAL: You MUST follow these steps IN ORDER. After collecting information for one step, AUTOMATICALLY move to the next step. Do NOT ask what the user wants to do - guide them through the process step by step.

Onboarding steps:
1. BRANDED TRACKING: Two subdomains (visit.clientdomain.com and statics.clientdomain.com).
FIRST: Get client name and company name if you don't have them yet.

IMPORTANT: You may ONLY extract a client name if the user explicitly says:
- "my name is Mark"
- "I'm Phil"
- "I am Alice"
- "this is Tom"
IF the user simply says "I am happy" or "yes I am happy", DO NOT treat this as a name.

THEN: IMMEDIATELY (without asking what they want) give this branded tracking paragraph:
"To combat the increasing challenges of Browser Privacy settings and Adblockers on tracking technology Tradedoubler has launched Branded Tracking. This solution will mask Tradedoubler tracking scripts under your own domain, preventing them from being disrupted. Branded Tracking also comes with the added benefit of masking publisher click links under your domain as well, creating a more positive user journey for consumers. 
To set this up, we will need two new subdomains — one for ad serving and one for tracking. You don't need to configure the subdomains on your end; we only require their names so we can register them in our system. Once the domain names are confirmed, I'll provide you with the CNAME DNS records needed to establish the connection."
AFTER: Ask for their website domain.
Once the client confirms they are happy with the subdomains, you MUST repeat the final branded domains explicitly (visit.[rootDomain] and statics.[rootDomain]) and say they have been sent to the technical team.

When confirming branded tracking domains, NEVER omit the domains. ALWAYS repeat both domains explicitly.

2. PRODUCT FEED:
- Ask for the feed URL
- Validate accessibility
- Once the feed link is provided, respond EXACTLY like:
"Perfect! I've received your product feed URL. I'm now connecting it to our AI-powered mapping system. I'll send you an email once it's complete. In the meantime, let's move on to uploading your program assets."

3. PROGRAM ASSETS:
- Logo (350x130)
- Ads (160x600, 300x250, 300x600, 728x90, 928x70)
- T&Cs

4. OFFICE IP ADDRESSES:
- Ask for IPs to blacklist internal staff

5. TRACKING SCRIPTS:
Say:
"Perfect! Now that your domains are confirmed, here are your tracking scripts:

📄 Implementation File: ${implementationUrl}

This file contains:
• Landing page script (for all pages)
• Confirmation page script (for thank-you/order confirmation page)
• Test link for verification

NEXT STEPS:
1. Integrate the scripts into your website following the instructions in the file
2. Once integrated, use the test link provided to complete a test transaction
3. This will verify that tracking is working correctly

Would you like me to walk you through the integration process, or do you have a developer who will handle this?"

IMPORTANT: GTM Preview Mode is ONLY for checking that tags fire correctly.
You CANNOT validate Tradedoubler tracking in Preview Mode because the test click link will not load inside preview and the pixel will not reach the Tradedoubler servers.

Real tracking tests MUST be done on the live site using the official Tradedoubler test link — outside of GTM Preview Mode.

IMPORTANT: Once the user confirms they have completed a test sale, say:
"Great! Thanks for testing. I have sent a message through to our technical team to verify if the tracking is live."

CRITICAL — TRACKING SCRIPT RULES:
IMPORTANT: Clarification about Google Tag Manager (GTM) usage:

Tradedoubler DOES allow the use of the GTM dataLayer, but ONLY for the purpose of 
passing dynamic transaction parameters (order number, order value, currency, 
voucher, products, etc.) into the GTM confirmation tag.

GTM's dataLayer is NOT used for firing Tradedoubler conversions.

The ONLY valid tracking mechanism is:
var TDConversion = {
  transactionId: '[ORDER_NUMBER]',
  ordervalue: '[ORDER_VALUE]',
  currency: '[CURRENCY]',
  event: [EVENT_ID],
  voucher: '[VOUCHER]',
  cdt: { extId: '[EXITID]', extType: 1 },
  validOn: '[VALID_ON]',
  products: '[PRODUCT_DATA]'
};
tdconv('track', 'sale', TDConversion);
tdfallback('https://a.imgstatic.eu/trsdk');

You MUST guide the user by referring to the Tradedoubler GTM manual.

Be warm, ask one question at a time, celebrate progress, and acknowledge information clearly.

Current progress:
- Client: ${onboardingData.clientName || 'Not provided'}
- Company: ${onboardingData.companyName || 'Not provided'}
- Completed steps: ${Object.values(checklist).filter(Boolean).length}/6
`;

// ----------------------------
// Messages
// ----------------------------
const messages = [
  { role: "system", content: systemPrompt },
  ...conversationHistory,
  { role: "user", content: userMessage }
];

// ----------------------------
// Return clean payload
// ----------------------------
return {
  messages,
  systemPrompt,
  userMessage,
  onboardingData,
  checklist,
  sessionId: body.sessionId || null
};

// Force SINGLE execution - log for debugging
const allItems = $input.all();
console.log("=== TAKE LAST ITEM ===");
console.log("Total items received:", allItems.length);

// Return ONLY the very last item
const lastItem = $input.last().json;
console.log("Returning last item:", { hasOutput: !!lastItem.output, hasText: !!lastItem.text });

return { json: lastItem };

// ----------------------------
// ALWAYS process only the final output of AI Agent
// ----------------------------
const input = $input.last().json;

// ----------------------------
// Extract AI response
// ----------------------------
const aiResponse = input.output || input.text || "";
const aiResponseLower = aiResponse.toLowerCase();

// ----------------------------
// Load onboarding data from Prepare Data (PERSISTENT)
// ----------------------------
let data = $('Prepare Data').item.json.onboardingData || {};

console.log("=== ONBOARDING DATA DEBUG ===");
console.log("Loaded data:", JSON.stringify(data, null, 2));

// ----------------------------
// Extract user message from Prepare Data
// ----------------------------
const userMessageRaw = $('Prepare Data').item.json.userMessage || "";
const userMessage = userMessageRaw.trim().toLowerCase();

// ----------------------------
// Name extraction (fixed to avoid "happy")
// ----------------------------
if (!data.clientName) {
  const nameMatch = userMessage.match(/\b(?:my name is|i am|i'm|im|this is)\s+([a-z]+)\b/i);
  if (nameMatch) {
    const extracted = nameMatch[1].toLowerCase();

    // Prevent false positives like "happy", "good", "ok"
    const invalidNames = ["happy", "ok", "test", "great", "fine", "good"];
    if (!invalidNames.includes(extracted)) {
      data.clientName = extracted.charAt(0).toUpperCase() + extracted.slice(1);
    }
  }
}

// ----------------------------
// Extract company
// ----------------------------
if (!data.companyName) {
  const companyMatch = userMessage.match(/\b(?:work at|from|with|representing|company)\s+([a-z0-9&\s]+)\b/i);
  if (companyMatch) {
    data.companyName = companyMatch[1].trim();
  }
}

// ----------------------------
// Root domain extraction
// ----------------------------
const domainMatch = userMessage.match(/([a-z0-9-]+\.[a-z]{2,}(?:\.[a-z]{2,})?)/i);
if (domainMatch) {
  const clean = domainMatch[0].replace(/^(https?:\/\/)?(www\.)?/, "");
  data.rootDomain = clean;
  data.visitSubdomain = `visit.${clean}`;
  data.staticsSubdomain = `statics.${clean}`;
}

// ----------------------------
// Product feed URL extraction
// ----------------------------
const linkMatch = userMessage.match(/https?:\/\/[^\s]+/i);
if (linkMatch && (userMessage.includes("feed") || userMessage.includes("product"))) {
  data.productFeedUrl = linkMatch[0];
}

// Detect feed format
if (data.productFeedUrl) {
  if (data.productFeedUrl.toLowerCase().endsWith(".xml")) {
    data.feedFormat = "XML";
  } else if (data.productFeedUrl.toLowerCase().endsWith(".csv")) {
    data.feedFormat = "CSV";
  }
}

// ----------------------------
// Extract IPs
// ----------------------------
if (userMessage.match(/\b\d{1,3}(\.\d{1,3}){3}\b/)) {
  const ips = userMessage.match(/\b\d{1,3}(\.\d{1,3}){3}\b/g);
  data.officeIPs = [...(data.officeIPs || []), ...ips];
}

console.log("=== DATA AFTER EXTRACTION ===");
console.log(JSON.stringify(data, null, 2));

// ----------------------------
// Detect branded tracking confirmation (ONLY PAST TENSE)
// ----------------------------
let triggerBrandedTrackingNotification = false;
let brandedVisitDomain = null;
let brandedStaticsDomain = null;

const brandedPatterns = [
  "sent to the technical team",
  "sent to our technical team",
  "forwarded to the technical team",
  "submitted to the technical team"
];

let matchedPattern = null;
brandedPatterns.forEach(pattern => {
  if (aiResponseLower.includes(pattern)) {
    matchedPattern = pattern;
  }
});

if (matchedPattern) {
  triggerBrandedTrackingNotification = true;

  const visitMatch = aiResponse.match(/visit\.[a-z0-9.-]+\.[a-z]{2,}/i);
  const staticsMatch = aiResponse.match(/statics\.[a-z0-9.-]+\.[a-z]{2,}/i);

  brandedVisitDomain = visitMatch?.[0] || null;
  brandedStaticsDomain = staticsMatch?.[0] || null;

  if (data.rootDomain) {
    if (!brandedVisitDomain) brandedVisitDomain = `visit.${data.rootDomain}`;
    if (!brandedStaticsDomain) brandedStaticsDomain = `statics.${data.rootDomain}`;
  }
}

// ----------------------------
// Detect product feed submission
// ----------------------------
let triggerProductFeedNotification = false;

const productFeedPatterns = [
  "received your product feed url",
  "i've received your product feed",
  "connecting it to our ai-powered mapping system"
];

productFeedPatterns.forEach(pattern => {
  if (aiResponseLower.includes(pattern) && data.productFeedUrl) {
    triggerProductFeedNotification = true;
  }
});

// ----------------------------
// Detect test sale completion
// ----------------------------
let triggerTestSaleNotification = false;

const testSaleUserPhrases = [
  "completed a test sale",
  "completed the test sale",
  "done a test sale",
  "finished the test",
  "completed a test"
];

const testSaleAiPatterns = [
  "sent a message through to our technical team to verify",
  "technical team to verify if the tracking is live"
];

const userMentionedTest = testSaleUserPhrases.some(phrase => userMessage.includes(phrase));
const aiConfirmedTest = testSaleAiPatterns.some(pattern => aiResponseLower.includes(pattern));

if (userMentionedTest && aiConfirmedTest) {
  triggerTestSaleNotification = true;
}

// ----------------------------
// FOLLOW-UP DETECTION
// ----------------------------
const postponementPhrases = [
  "not ready", "later", "another time", "set this up later",
  "come back", "not yet", "few days", "don't have this right now"
];

let followUp = null;

if (postponementPhrases.some((phrase) => userMessage.includes(phrase))) {
  const followUpDate = new Date();
  followUpDate.setDate(followUpDate.getDate() + 3);

  followUp = {
    reason: "user_postponed_step",
    follow_up_at: followUpDate.toISOString(),
    original_message: userMessageRaw
  };
}

// ----------------------------
// Checklist
// ----------------------------
const checklist = {
  intro: !!(data.clientName && data.companyName),
  brandedTracking: !!data.rootDomain,
  productFeed: !!data.productFeedUrl,
  assets: false,
  ipAddresses: !!(data.officeIPs && data.officeIPs.length > 0),
  trackingScripts: false
};

const isComplete = Object.values(checklist).every(Boolean);

// ----------------------------
// Return — ONLY 1 ITEM
// ----------------------------
return [
  {
    json: {
      response: aiResponse,
      onboardingData: data,
      checklist,
      isComplete,
      triggerBrandedTrackingNotification,
      brandedVisitDomain,
      brandedStaticsDomain,
      triggerProductFeedNotification,
      triggerTestSaleNotification,  
      followUp
    }
  }
];

// FORCE SINGLE ITEM - second filter
const allItems = $input.all();
console.log("=== FORCE SINGLE ITEM (After Process) ===");
console.log("Items received:", allItems.length);

if (allItems.length > 1) {
  console.log("⚠️ WARNING: Received", allItems.length, "items! Should be 1!");
}

// Return ONLY the last item
return { json: $input.last().json };

return {
  response: $('Process Data').item.json.response,
  onboardingData: $('Process Data').item.json.onboardingData,
  checklist: $('Process Data').item.json.checklist,
  isComplete: $('Process Data').item.json.isComplete,
  followUp: $('Process Data').item.json.followUp
};

const processData = $input.item.json;
const prepareData = $('Prepare Data').item.json;

const conversationHistory = prepareData.messages || [];
const userMessage = prepareData.userMessage || "";
const aiResponse = processData.response || "";
const checklist = processData.checklist || {};
const onboardingData = processData.onboardingData || {};

console.log("=== DETECTING LEARNING MOMENTS ===");

const learningMoments = [];
const userLower = userMessage.toLowerCase();
const aiLower = aiResponse.toLowerCase();

// 1. BRANDED TRACKING EXPLAINED SUCCESSFULLY
if (checklist.brandedTracking && onboardingData.rootDomain) {
  const previousData = $('Prepare Data').item.json.onboardingData || {};
  const isFirstTime = !previousData.rootDomain && onboardingData.rootDomain;

  if (isFirstTime) {
    learningMoments.push({
      category: 'branded_tracking_explanation',
      step: 'brandedTracking',
      user_context: userMessage,
      agent_response: aiResponse,
      outcome: 'client_provided_domain',
      reason: 'Client successfully understood and provided their domain',
      conversation_excerpt: conversationHistory.slice(-4).filter(m => m.role !== 'system')
    });
    console.log("✅ Detected: Successful branded tracking explanation");
  }
}

// 2. DNS/CNAME CONFUSION RESOLVED
const dnsConfusionIndicators = [
  'confused', 'don\'t understand', 'not sure how', 'what is cname',
  'how do i', 'never done this', 'can you explain'
];
const dnsTopics = ['cname', 'dns', 'record', 'subdomain', 'domain'];

const userShowsConfusion = dnsConfusionIndicators.some(phrase => userLower.includes(phrase));
const aboutDNS = dnsTopics.some(topic => userLower.includes(topic) || aiLower.includes(topic));

if (userShowsConfusion && aboutDNS && aiResponse.length > 100) {
  learningMoments.push({
    category: 'dns_confusion_resolved',
    step: 'brandedTracking',
    user_context: userMessage,
    agent_response: aiResponse,
    outcome: 'confusion_addressed',
    reason: 'Agent provided helpful explanation to confused client',
    conversation_excerpt: conversationHistory.slice(-3).filter(m => m.role !== 'system')
  });
  console.log("✅ Detected: DNS confusion resolved");
}

// 3. GTM IMPLEMENTATION CLARITY
const gtmTopics = ['gtm', 'google tag manager', 'tag', 'preview'];
const aboutGTM = gtmTopics.some(topic => userLower.includes(topic) || aiLower.includes(topic));
const agentClarifiedPreview = aiLower.includes('preview mode') && 
                              (aiLower.includes('cannot') || aiLower.includes('live site'));

if (aboutGTM && agentClarifiedPreview) {
  learningMoments.push({
    category: 'gtm_implementation_guidance',
    step: 'trackingScripts',
    user_context: userMessage,
    agent_response: aiResponse,
    outcome: 'gtm_clarification_provided',
    reason: 'Agent clarified GTM preview mode limitations',
    conversation_excerpt: conversationHistory.slice(-3).filter(m => m.role !== 'system')
  });
  console.log("✅ Detected: GTM implementation clarity provided");
}

// 4. PRODUCT FEED SUBMISSION
if (processData.triggerProductFeedNotification && onboardingData.productFeedUrl) {
  learningMoments.push({
    category: 'product_feed_submission',
    step: 'productFeed',
    user_context: userMessage,
    agent_response: aiResponse,
    outcome: 'feed_url_provided',
    reason: 'Client successfully provided product feed URL',
    conversation_excerpt: conversationHistory.slice(-2).filter(m => m.role !== 'system')
  });
  console.log("✅ Detected: Product feed submission");
}

// 5. DELAY HANDLED GRACEFULLY
if (processData.followUp !== null) {
  learningMoments.push({
    category: 'delay_handling',
    step: 'general',
    user_context: userMessage,
    agent_response: aiResponse,
    outcome: 'follow_up_scheduled',
    reason: 'Agent gracefully handled client delay request',
    conversation_excerpt: conversationHistory.slice(-2).filter(m => m.role !== 'system')
  });
  console.log("✅ Detected: Graceful delay handling");
}

// 6. TRACKING TEST COMPLETION
if (processData.triggerTestSaleNotification) {
  learningMoments.push({
    category: 'tracking_test_completion',
    step: 'trackingScripts',
    user_context: userMessage,
    agent_response: aiResponse,
    outcome: 'test_completed',
    reason: 'Client successfully completed tracking test',
    conversation_excerpt: conversationHistory.slice(-3).filter(m => m.role !== 'system')
  });
  console.log("✅ Detected: Tracking test completion");
}

// 7. IP ADDRESSES PROVIDED
if (onboardingData.officeIPs && onboardingData.officeIPs.length > 0) {
  const previousIPs = $('Prepare Data').item.json.onboardingData?.officeIPs || [];
  const newIPs = onboardingData.officeIPs.filter(ip => !previousIPs.includes(ip));

  if (newIPs.length > 0) {
    learningMoments.push({
      category: 'ip_collection',
      step: 'ipAddresses',
      user_context: userMessage,
      agent_response: aiResponse,
      outcome: 'ips_provided',
      reason: 'Client provided office IP addresses',
      conversation_excerpt: conversationHistory.slice(-2).filter(m => m.role !== 'system')
    });
    console.log("✅ Detected: IP addresses provided");
  }
}

// 8. CLIENT SATISFACTION
const satisfactionIndicators = [
  'perfect', 'great', 'excellent', 'thank you', 'thanks',
  'that makes sense', 'got it', 'understood', 'clear now'
];

const clientSatisfied = satisfactionIndicators.some(phrase => userLower.includes(phrase));

if (clientSatisfied && aiResponse.length > 50) {
  learningMoments.push({
    category: 'positive_interaction',
    step: 'general',
    user_context: userMessage,
    agent_response: aiResponse,
    outcome: 'client_satisfaction',
    reason: 'Client expressed satisfaction with explanation',
    conversation_excerpt: conversationHistory.slice(-2).filter(m => m.role !== 'system')
  });
  console.log("✅ Detected: Client satisfaction");
}

console.log(`📊 Total learning moments detected: ${learningMoments.length}`);

if (learningMoments.length === 0) {
  return [];
}

return learningMoments.map(moment => ({
  json: {
    ...moment,
    program_id: onboardingData.programId || null,
    session_id: prepareData.sessionId || null,
    client_name: onboardingData.clientName || null,
    company_name: onboardingData.companyName || null,
    timestamp: new Date().toISOString()
  }
}));

const learningMoment = $('Detect Learning Moments').item.json;
const embeddingResponse = $input.item.json;

console.log("=== PROCESSING EMBEDDING RESPONSE ===");
console.log("Learning moment category:", learningMoment.category);

let embedding;

if (embeddingResponse.data && embeddingResponse.data[0]) {
  embedding = embeddingResponse.data[0].embedding;
} else if (embeddingResponse.embedding) {
  embedding = embeddingResponse.embedding;
} else if (Array.isArray(embeddingResponse)) {
  embedding = embeddingResponse;
} else {
  console.error("❌ Unexpected embedding format:", embeddingResponse);
  throw new Error("Could not extract embedding from response");
}

console.log("✅ Embedding extracted, length:", embedding.length);

const embeddingString = `[${embedding.join(',')}]`;
const conversationExcerpt = JSON.stringify(learningMoment.conversation_excerpt || []);

return {
  json: {
    category: learningMoment.category,
    step: learningMoment.step,
    user_context: learningMoment.user_context,
    agent_response: learningMoment.agent_response,
    outcome: learningMoment.outcome,
    conversation_excerpt: conversationExcerpt,
    program_id: learningMoment.program_id,
    session_id: learningMoment.session_id,
    client_name: learningMoment.client_name,
    company_name: learningMoment.company_name,
    embedding: embeddingString
  }
};

// ----------------------------
// Get incoming data
// ----------------------------
const body = $input.item.json.body || {};

const userMessage = body.message || "";
const conversationHistory = body.conversationHistory || [];
const onboardingData = body.onboardingData || {};
const checklist = body.checklist || {};

// ------------------------------------------------
// PROGRAM ID HANDLING (reliable + persistent)
// ------------------------------------------------
let programId = body.programId || onboardingData.programId || null;

// Only save programId if valid (avoid undefined/N/A)
if (programId) {
  onboardingData.programId = programId;
}

// Dynamic implementation URL (safe fallback)
let implementationUrl = "";
if (onboardingData.programId) {
  implementationUrl = `https://hst.tradedoubler.com/file/${onboardingData.programId}/implementation.html`;
}

// ------------------------------------------------
// SAFETY RULE: Prevent mistakes in client name extraction
// ------------------------------------------------
onboardingData.disallowedNames = [
  "happy", "good", "ok", "great", "fine", "yes", "yep", "sure", "okay"
];

// ============================================
// NEW: SEARCH FOR SIMILAR PATTERNS
// ============================================

let learningContext = "";

// Only search if user message has substance
if (userMessage.trim().length > 10) {
  // Detect current topic for filtering
  const userLower = userMessage.toLowerCase();

  if (userLower.includes('cname') || userLower.includes('dns') || userLower.includes('subdomain')) {
    learningContext = `

📚 LEARNING FROM PAST SUCCESSES:
When clients ask about DNS/CNAME setup, successful approaches include:
- Using simple analogies (e.g., "CNAME is like forwarding mail to a different address")
- Emphasizing that they're just creating a forwarding rule, not building anything
- Offering to share DNS provider-specific instructions if they need help
- Being patient and breaking it down step by step
`;
  } else if (userLower.includes('gtm') || userLower.includes('tag manager') || userLower.includes('preview')) {
    learningContext = `

📚 LEARNING FROM PAST SUCCESSES:
For GTM questions, successful approaches include:
- Clearly stating that GTM Preview Mode CANNOT validate Tradedoubler tracking
- Explaining that the test MUST be done on the live site using the official test link
- Emphasizing that Preview Mode only confirms tags fire, but doesn't reach TD servers
- Offering to walk them through the proper testing process step by step
`;
  } else if (userLower.includes('confused') || userLower.includes('not sure') || userLower.includes('don\'t understand')) {
    learningContext = `

